-- ── Blackboard Learn ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enterprise learning management system for higher education and K-12, offering the Ultra course experience, accessibility tools, and AI-assisted course design.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(1997, founded_year),
  company_size = COALESCE($q$1,000+ employees (Anthology)$q$, company_size),
  headquarters = COALESCE($q$Boca Raton, Florida, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Chinese$q$, $q$Arabic$q$]::text[],
  seo_title = COALESCE($q$Blackboard Learn Review 2026: Features, Pricing & Ultra$q$, seo_title),
  seo_meta_description = COALESCE($q$Blackboard Learn is Anthology's enterprise LMS for higher education and K-12. See Ultra course view features, pricing structure, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blackboard Learn is a learning management system originally launched by Blackboard Inc. in 1997 and now developed by Anthology, Inc., formed when Blackboard merged with Anthology in late 2021. Anthology is headquartered in Boca Raton, Florida, and operates offices across North America and internationally, with over 1,000 employees. Blackboard Learn is used primarily by colleges, universities, and K-12 school systems to deliver online and blended courses, manage gradebooks and assignments, host discussion boards, and track student progress. The product's modern interface, called the Ultra Course View, replaced the older Original Course View with a mobile-first, more accessible design; Ultra adds features such as Progress Tracking, Discussion Analytics, streamlined navigation, and a redesigned gradebook. Blackboard also integrates Ally, an accessibility tool that scans course content for accessibility issues and automatically generates alternative formats such as audio, ePub, and translated versions for students with different needs. More recently, Anthology introduced an Ultra AI Design Assistant intended to help instructors draft course structures, learning objectives, and content more quickly. Blackboard Learn does not publish fixed, self-serve pricing; instead, Anthology sells the platform through sales-led, negotiated institutional contracts, with cost varying based on enrollment size, deployment model (cloud-hosted SaaS versus self-hosted), and the bundle of Anthology products purchased alongside Learn. Publicly available reference points vary: some third-party pricing trackers cite entry-level annual contracts in the range of several thousand dollars, while public-sector procurement frameworks in the UK have cited per-user annual pricing in double-digit pound amounts structured around fixed user bands rather than per-seat metering. Because of this, institutions evaluating Blackboard Learn should expect to request a custom quote rather than relying on published list pricing. Blackboard Learn provides native mobile apps for iOS and Android that let students access course materials, submit assignments, view grades, and receive push notifications for deadlines and announcements. The platform supports integrations with common higher-ed systems such as student information systems (SIS) through LTI (Learning Tools Interoperability) standards, allowing it to connect with third-party publisher content, proctoring tools, and video platforms. Blackboard Learn competes with other major higher-education and enterprise LMS platforms including Canvas (Instructure), Moodle, D2L Brightspace, and Schoology, and it remains one of the longest-established players in the category given its 1997 founding, though its user experience and market positioning have shifted substantially since the Anthology merger consolidated it with Anthology's other education technology products such as student information and CRM systems.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5f612c37-64e2-4aeb-a2a0-9b6d63df09b4';

