-- ── blocky ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source DNS proxy and ad-blocker written in Go for self-hosted, network-wide blocking of ads, trackers, and malware domains.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$blocky Review: Self-Hosted DNS Ad Blocker Features$q$, seo_title),
  seo_meta_description = COALESCE($q$blocky is a free, open-source DNS proxy for network-wide ad and tracker blocking. See features, self-hosting setup, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$blocky is a free and open-source DNS proxy and ad-blocker built in the Go programming language, distributed via its GitHub repository at 0xERR0R/blocky under an open-source license. It runs as a self-hosted service on a local network, typically on a home server, Raspberry Pi, or NAS device, and functions by intercepting DNS queries from every device on the network and filtering out requests to known ad, tracker, and malware domains before they resolve. Unlike commercial ad-blocking services, blocky is built and maintained by volunteer contributors in their spare time and explicitly states it collects no telemetry and shares no data with any third party. Because it operates at the DNS layer rather than as a browser extension, blocky blocks ads and trackers across every application and device on the network simultaneously, including smart TVs, mobile apps, and IoT devices that browser-based ad blockers cannot reach. Core filtering capabilities include domain-based blocklists, deep CNAME inspection (blocking based on the CNAME a domain resolves to, which catches cloaked or disguised tracking domains), and IP-based blocking against configurable IP address lists. blocky supports modern encrypted DNS protocols including DNS-over-HTTPS (DoH), DNS-over-TLS (DoT), and DNS-over-QUIC (DoQ), letting administrators both consume and serve DNS queries over encrypted channels rather than legacy unencrypted DNS. It also supports DNSSEC validation and eDNS extensions for compatibility with modern DNS infrastructure. For monitoring, blocky can log DNS queries per client and per day, either to local CSV files or to a relational database such as MySQL, MariaDB, PostgreSQL, or TimescaleDB, and it exposes metrics in a format compatible with Prometheus for integration into existing monitoring and alerting stacks such as Grafana dashboards. As a self-hosted, configuration-file-driven tool, blocky is typically deployed via Docker or as a standalone binary and configured through a YAML configuration file rather than a graphical setup wizard, which makes it best suited to users who are comfortable with basic server administration, Docker, and editing configuration files, rather than non-technical consumers looking for a plug-and-play appliance. It is frequently compared to and sometimes used alongside similar self-hosted DNS ad-blocking tools such as Pi-hole and AdGuard Home; blocky differentiates itself primarily through its lightweight Go-based implementation, deep CNAME inspection, native support for encrypted DNS protocols, and flexible database-backed query logging options. Because it has no company behind it, no pricing tiers, and no customer support organization, all support is provided informally through its GitHub issue tracker and community contributions, and users are fully responsible for their own deployment, updates, and maintenance.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '68da8924-7233-4187-b3c7-8e5486ea5ee0';

