-- ── Blot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Blogging platform with no interface that turns a Dropbox or GitHub folder into a website, letting you publish by simply adding files.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$6/month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Blot Review 2026: Pricing, Features & How It Works$q$, seo_title),
  seo_meta_description = COALESCE($q$Blot turns a Dropbox or GitHub folder into a website for $6/month. See how the no-interface blogging platform works, its features, and open-source option.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blot is a blogging platform built by developer David Merfield, who wrote its first code in the summer of 2013 and made it publicly available in 2014. Blot's defining characteristic is that it has no traditional content management interface: instead of logging into a dashboard to write posts, users connect a folder in Dropbox, Google Drive, or a GitHub repository, and any file dropped into that folder, whether a Word document, Markdown file, plain text file, or image, is automatically converted into a published page or blog post on a live website. Deleting or editing the file in the folder updates or removes the corresponding page. The entire site structure, including nested pages and categories, can be managed just by organizing folders and subfolders within the connected cloud storage folder, without touching any web-based editor. This design is explicitly framed by its creator as an attempt to revive the simplicity of early personal publishing on services like GeoCities and Myspace, while still producing a modern, themeable, fast-loading website. Blot supports Markdown formatting, custom domains, and a library of templates/themes that can be customized with HTML and CSS for users who want more control over design. Blot's hosted service costs $6 per month per site, which covers hosting, access to all available templates, custom domain support, SSL certificates, and customer support; pricing pages do not advertise a free trial, so new users generally sign up for the paid plan directly. In addition to the hosted service, Blot is an open-source project, with its full source code published on GitHub at davidmerfield/Blot, allowing technically capable users to self-host their own instance of the platform rather than paying for Blot's hosted infrastructure. This dual model, a small indie-run paid hosted service backed by an open-source codebase, means Blot has no formal company structure, headquarters, or employee count in the way a typical SaaS company does; it is maintained largely as a solo or small-team project rather than a venture-backed startup. Blot's target audience is writers, indie hackers, and technically comfortable individuals who want to publish a blog or personal website without learning a CMS dashboard, and who are already comfortable working with files in Dropbox, Google Drive, or Git. It is not designed for team-based content workflows, e-commerce, or complex site architectures, and it lacks the plugin ecosystems of larger platforms like WordPress; its value proposition is minimalism and a frictionless, file-based publishing workflow rather than breadth of features.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '53ba4185-9c98-4925-94b6-7aa6336c54d0';

