-- ── Blubrry ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Podcast hosting platform with IAB-certified analytics, WordPress integration, and unlimited-downloads plans, founded by podcasting pioneer Todd Cochrane.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Blubrry Review 2026: Podcast Hosting Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Blubrry is a podcast hosting platform with plans from $15/month plus free IAB-certified statistics. See features, pricing tiers, and WordPress integration.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blubrry Podcasting was founded in 2005 by podcast pioneer Todd Cochrane, making it one of the earliest podcast hosting companies still operating today, having marked over 20 years in the industry. Cochrane served as CEO until his death in September 2025, after building the company around open RSS-based podcast distribution since the medium's early days. Blubrry's core product is podcast media hosting: creators upload audio files which Blubrry distributes to podcast directories and apps including Apple Podcasts and Spotify, generating the RSS feed that podcast platforms use to syndicate episodes. Hosting plans are tiered by monthly upload storage rather than by download volume. The Standard plan costs $15 per month and includes 125 MB of monthly uploads, roughly two hours of audio. The Advanced plan, Blubrry's most popular tier, costs $25 per month and includes 400 MB of monthly uploads, roughly seven hours of audio, along with deeper audience analytics and episode performance tools. The Professional plan costs $100 per month and offers unlimited uploads, support for managing multiple shows and users, advanced monetization tools, and dynamic ad insertion, aimed at podcast networks and commercial publishers. All hosting plans include unlimited listens regardless of upload tier, distribution to major podcast platforms, a free companion WordPress website, a custom embeddable player, AI-assisted podcasting tools, and free migration assistance for podcasters moving from another host. Separately from hosting, Blubrry offers standalone podcast statistics plans for creators who host elsewhere but want Blubrry's analytics: a Free Statistics tier tracks basic downloads, audience location, and listener trends; a Standard Statistics tier at $5 per month adds full audience and device breakdowns and the ability to compare the three most recent episodes; and Advanced Statistics, bundled with the Advanced hosting plan, adds full five-episode comparison, listener retention curves, partial-play data, and estimated subscriber counts. All of Blubrry's statistics are IAB (Interactive Advertising Bureau) certified, a standard many podcast networks and advertisers require for verified download and audience reporting used in ad sales. Blubrry is also known in the WordPress ecosystem for its PowerPress plugin, which integrates podcast publishing and hosting directly into a WordPress site. The company's positioning emphasizes being run by people with deep roots in podcasting rather than a broader media conglomerate, and it markets itself toward independent podcasters, small networks, and WordPress-based publishers who want IAB-certified analytics without committing to the highest-priced enterprise podcast hosting platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e';

