-- ── Bludit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source flat-file CMS that stores content as JSON files instead of a database, built for fast, simple blogs and small websites.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Bludit Review 2026: Flat-File CMS Features & Setup$q$, seo_title),
  seo_meta_description = COALESCE($q$Bludit is a free, open-source flat-file CMS storing content as JSON with no database required. See features, plugins, themes, and who it's built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bludit is a free, open-source content management system that has been in active development since 2015, distributed under the MIT license and maintained on GitHub at bludit/bludit. Its defining architectural feature is that it is a flat-file CMS: rather than requiring a MySQL or other relational database, Bludit stores all pages, posts, categories, tags, and settings as JSON files directly on the file system. This makes installation and deployment simpler than database-driven platforms like WordPress, since the only server requirement is PHP (version 7 or higher) along with standard PHP extensions such as mbstring for UTF-8 support, GD for image processing, DOM for markup manipulation, and JSON for content parsing; there is no database server to configure, back up, or maintain. Bludit supports both a Markdown editor and a WYSIWYG (rich text) editor for writing content, and it accepts raw HTML within posts and pages as well. The current stable release line is version 3.x, distributed as a web-based installer or via Docker for containerized deployment. Like WordPress, Bludit can be extended through an ecosystem of community-built plugins and themes distributed through an official plugins directory (plugins.bludit.com) and companion theme repositories, covering functionality such as contact forms, RSS feeds, image galleries, and SEO tools; the core software also ships with built-in SEO tools and is described by its maintainers as privacy-first, tracking no visitor data by default and positioned as GDPR-compliant out of the box. Because it is entirely self-hosted and open source, Bludit has no company, pricing plans, or commercial support organization behind it; users install it on their own web hosting or server and rely on community documentation and forums for support. One limitation frequently noted by users is that Bludit's admin interface does not have robust built-in multi-language switching for the interface itself, meaning fully multilingual sites typically require third-party community plugins, such as a Multilingual and Multi Blogs plugin, or separate parallel installations per language, rather than a native language-switching feature. Bludit is best suited for small to medium websites, portfolios, documentation sites, and personal or small-business blogs where an administrator wants a fast, low-maintenance CMS without the operational overhead of a database, rather than for large multi-author publications or e-commerce sites, which are better served by more feature-complete platforms like WordPress. It is commonly grouped with other flat-file CMS options such as Grav and Kirby as an alternative to database-backed systems for developers and site owners who prioritize simplicity, speed, and minimal server requirements.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2dacf89b-e2ef-4c5b-abc5-d221801f171b';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '2dacf89b-e2ef-4c5b-abc5-d221801f171b' AND logo IS NULL AND website IS NOT NULL;

DELETE FROM tool_features WHERE tool_id = '2dacf89b-e2ef-4c5b-abc5-d221801f171b';

