DELETE FROM tool_cons WHERE tool_id = '2dacf89b-e2ef-4c5b-abc5-d221801f171b';

DELETE FROM tool_faqs WHERE tool_id = '2dacf89b-e2ef-4c5b-abc5-d221801f171b';

