INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$End-to-end encrypted vault$q$, $q$Passwords, passkeys, and notes are encrypted client-side with AES-256 before syncing, using a zero-knowledge architecture.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Passkey support$q$, $q$Users can generate, store, and log in with FIDO2 passkeys, plus use security keys or biometrics for two-step login.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Cross-platform apps$q$, $q$Native apps and browser extensions cover Windows, macOS, Linux, iOS, Android, and all major browsers, plus a CLI.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Self-hosting$q$, $q$The full Bitwarden server stack can be self-hosted via Docker for organizations that need to control their own infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Secure sharing and organizations$q$, $q$Business plans let admins group logins into shared collections with role-based permissions across teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Directory sync and SCIM$q$, $q$Enterprise and Teams plans sync users from Azure AD, Okta, and other identity providers and automate provisioning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Vault health reports$q$, $q$Premium and business plans include reports that flag weak, reused, or exposed passwords across the vault.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Secrets manager$q$, $q$A separate product for storing and rotating API keys and other machine credentials used by developer teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Free plan is unusually generous, with unlimited passwords and devices at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Open-source code base has undergone multiple independent third-party security audits$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Self-hosting option available for organizations with strict compliance or data-residency needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Broad platform coverage across desktop, mobile, and every major browser$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Interface is more utilitarian than some paid competitors like 1Password$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Some advanced features (emergency access, file attachments) require a paid plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Business features such as SSO and account recovery are gated to the Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Community self-hosting setup requires comfort with Docker and server administration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Is Bitwarden really free?$q$, $q$Yes. The Free plan has no time limit and includes unlimited passwords across unlimited devices, though some features like file attachments and emergency access require Premium.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Is Bitwarden open source?$q$, $q$Yes. Bitwarden publishes the source code for its clients and server, which allows independent security audits and supports self-hosted deployments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Can Bitwarden be self-hosted?$q$, $q$Yes, Bitwarden offers a self-hosting option that lets organizations run the full server stack on their own infrastructure, available with a paid license for organizational use.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Does Bitwarden support passkeys?$q$, $q$Yes. Bitwarden can generate, store, and use passkeys for logging into supported websites, and can also use security keys and passkeys for two-step login into the Bitwarden account itself.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$How much does Bitwarden cost for a team?$q$, $q$Business pricing starts at $4 per user per month for the Teams plan and $6 per user per month for Enterprise, both billed annually.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Individual password security$q$, $q$A single user replaces browser-saved passwords and weak reused credentials with an encrypted vault and generated passwords.$q$, $q$Individuals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Family credential sharing$q$, $q$A household shares logins for streaming, banking, and shared accounts securely across up to six family members.$q$, $q$Families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Company-wide credential management$q$, $q$IT and security teams centralize employee credential storage with SSO, directory sync, and audit logging for compliance.$q$, $q$Businesses and IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, NULL, $q$["Unlimited passwords","Unlimited devices","Secure sharing with 1 person","Password generator"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Premium$q$, $q$$1.65/month$q$, $q$Billed annually ($19.80/year)$q$, NULL, $q$["Integrated authenticator","File attachments","Emergency access","Vault health reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Families$q$, $q$$3.99/month$q$, $q$Billed annually ($47.88/year)$q$, NULL, $q$["Up to 6 users","All Premium features per member","Unlimited sharing and collections"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Teams$q$, $q$$4/user/month$q$, $q$Billed annually$q$, NULL, $q$["Secure credential sharing","Event log auditing","Directory sync","SCIM provisioning"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$Enterprise$q$, $q$$6/user/month$q$, $q$Billed annually$q$, NULL, $q$["All Teams features","SSO integration","Granular access control","Account recovery","Free Families plan for all users"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bitwarden is an open-source password manager founded in 2015 and based in Santa Barbara, California. It encrypts and stores passwords, passkeys, two-factor authentication codes, and secure notes in a vault that syncs across browser extensions, mobile apps, desktop apps, and a web interface.$q$, $q$Because the source code for both its clients and server is public, Bitwarden has been repeatedly audited by independent security firms, and it offers a self-hosting option for organizations that want to run the backend on their own infrastructure rather than Bitwarden's cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bitwarden's vault uses end-to-end encryption with a zero-knowledge architecture, meaning the master password and unencrypted data never leave the user's device unencrypted. It supports passkey login and storage, an integrated TOTP authenticator for two-step login codes, encrypted file attachments, and a password generator with configurable complexity rules.$q$, $q$For teams and enterprises, Bitwarden adds secure item sharing through organizations and collections, directory synchronization with tools like Azure AD and Okta, SCIM provisioning, SSO login, event log auditing, and an Access Intelligence feature that surfaces weak, reused, or exposed credentials across an organization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bitwarden's Free plan has no time limit and covers unlimited passwords on unlimited devices. Premium is $1.65 per month billed annually and adds file attachments, an integrated authenticator, and emergency access. Families is $3.99 per month billed annually for up to six people.$q$, $q$Business pricing starts with Teams at $4 per user per month, adding directory sync and audit logs, and Enterprise at $6 per user per month, adding SSO, self-hosting flexibility, and account recovery. All paid plans bill annually.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
