INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Event Experience OS$q$, $q$A unified platform covering event websites, registration, ticketing, email marketing, and reporting in one system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Klik SmartBadges$q$, $q$Wearable event badges enabling click-to-connect networking, automated lead capture, and live attendee movement analytics.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Mobile event apps$q$, $q$Native iOS and Android apps let attendees view agendas, check in to sessions, and network with other attendees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Sponsor and exhibitor management$q$, $q$Tools for managing sponsor packages, booth assignments, and measurable lead capture and engagement ROI.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Hybrid and virtual event support$q$, $q$Live streaming, virtual session hosting, and networking features for hybrid or fully virtual events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Reporting and analytics$q$, $q$Post-event reporting on registration, engagement, and sponsor performance, plus live analytics during onsite events.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$End-to-end platform reduces the need for multiple separate event tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Klik SmartBadge hardware differentiates Bizzabo for large in-person conferences$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Native mobile apps for both iOS and Android support attendee engagement$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Backed by an established company with 300+ employees and a track record since 2011$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Pricing starts near $18,000 per year, out of reach for small event organizers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$No public free plan; pricing requires contacting sales$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Klik SmartBadge is best suited to large events of 500+ attendees, less relevant for smaller ones$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Full pricing for add-ons and professional services is not publicly listed$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$How much does Bizzabo cost?$q$, $q$The core Event Experience OS starts at $17,999 per year, billed annually with a three-user minimum. Klik SmartBadge and add-ons like virtual production or API access are priced separately by quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Does Bizzabo offer a free trial?$q$, $q$Bizzabo does not publish self-serve free trial pricing; prospective customers typically request a demo before purchasing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$What is Klik SmartBadge?$q$, $q$Klik is Bizzabo's wearable event badge product that enables click-to-connect networking, automated sponsor lead capture, and live attendee analytics, priced separately from the core platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Who founded Bizzabo?$q$, $q$Bizzabo was founded in 2011 by Boaz Katz, Alon Alroy, and Eran Ben-Shushan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Does Bizzabo have a mobile app?$q$, $q$Yes, Bizzabo provides native iOS and Android event apps for attendees to view agendas, check in, and network.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Enterprise B2B conferences$q$, $q$Corporate marketing and events teams run large annual flagship conferences with integrated registration, agenda, and sponsor management.$q$, $q$Enterprise event marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Hybrid conference production$q$, $q$Organizers combine in-person attendance with livestreamed virtual sessions on a single registration and content platform.$q$, $q$Hybrid event producers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Sponsor-driven trade shows$q$, $q$Event organizers use Klik SmartBadges to give sponsors measurable lead capture and booth engagement data.$q$, $q$Trade show and exhibition organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Event Experience OS$q$, $q$From $17,999/year$q$, $q$Annual, 3-user minimum$q$, NULL, $q$["Unlimited events and registrations","Event website builder","Email campaigns","Mobile app","Reporting and analytics","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$Klik SmartBadge$q$, $q$Custom quote$q$, $q$Single or multi-event$q$, NULL, $q$["Wearable smart badges","Click-to-connect networking","Lead capture and gamification","Live attendee analytics"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bizzabo was founded in 2011 by Boaz Katz, Alon Alroy, and Eran Ben-Shushan and is headquartered jointly in New York City and Tel Aviv, with additional offices in Kyiv and London. The company launched its full event management platform in 2015 and now employs more than 300 people.$q$, $q$The platform, marketed as the Event Experience OS, is designed for B2B conferences and corporate events, combining registration, event websites, mobile apps, and onsite engagement tools such as Klik SmartBadges into a single system rather than requiring organizers to stitch together separate point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include a drag-and-drop event website builder, attendee registration and ticketing workflows, email marketing campaigns, agenda and speaker management, contact and CRM tools, and native mobile apps for iOS and Android that let attendees check in and network.$q$, $q$Onsite and hybrid events can use Klik SmartBadges, wearable badges that enable click-to-connect networking, automated sponsor lead capture, and live movement and engagement analytics through venue beacons, in addition to standard livestreaming and virtual session tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Event Experience OS starts at $17,999 per year, based on a three-user minimum and billed annually, positioning Bizzabo toward mid-market and enterprise events teams rather than individual organizers. Klik SmartBadge hardware and software are quoted separately for single or multi-event use.$q$, $q$Additional add-ons such as virtual event production, custom-branded apps, API access, and SSO are available at extra cost, and Bizzabo offers professional services like onsite production support through Bizzabo Studios at variable, quote-based pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ef81f2cc-5d19-4029-abc4-98bb85afba1c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Ultra Course View$q$, $q$A modern, mobile-first course interface with streamlined navigation, progress tracking, and discussion analytics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Ally accessibility tools$q$, $q$Automatically scans course content for accessibility issues and generates alternative formats like audio and ePub.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Ultra AI Design Assistant$q$, $q$AI-assisted course design tool that helps instructors draft course structure and content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Gradebook and assignments$q$, $q$Centralized grading, rubrics, and assignment submission and feedback workflows for instructors and students.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Discussion boards and messaging$q$, $q$Threaded discussion tools and in-course messaging to support communication between students and instructors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$LTI integrations$q$, $q$Connects with third-party publisher content, proctoring services, and video platforms via LTI standards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Mobile apps$q$, $q$Native iOS and Android apps let students view grades, submit work, and get deadline notifications.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Long track record and wide adoption across higher education since 1997$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Ultra Course View significantly modernized the interface and mobile experience$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Strong built-in accessibility tooling via Ally$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Broad LTI-based integration ecosystem with publisher and proctoring tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$No public pricing; requires a sales-led quote for every institution$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Legacy Original Course View can still create a fragmented experience during Ultra migration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Enterprise deployment and administration can require significant IT involvement$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Primarily built for institutions, not well suited to individual educators or small training providers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$How much does Blackboard Learn cost?$q$, $q$Blackboard Learn does not publish fixed pricing. Anthology negotiates contracts per institution based on enrollment size and deployment model, so pricing requires a custom quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Is Blackboard Learn the same as Anthology?$q$, $q$Anthology is the company that develops Blackboard Learn, formed when Blackboard Inc. merged with Anthology in late 2021. Blackboard Learn remains one of Anthology's core products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$What is the Ultra Course View?$q$, $q$Ultra is Blackboard's modern, mobile-first course interface that replaced the older Original Course View, adding features like progress tracking and discussion analytics.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Does Blackboard Learn have a mobile app?$q$, $q$Yes, native Blackboard apps are available for iOS and Android, letting students view grades, submit assignments, and receive notifications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Does Blackboard Learn support accessibility features?$q$, $q$Yes, through its integrated Ally tool, which scans course content and automatically generates alternative formats for students with accessibility needs.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Higher education online courses$q$, $q$Colleges and universities deliver blended and fully online courses with gradebooks, discussions, and assignment submission.$q$, $q$Universities and colleges$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$K-12 blended learning$q$, $q$School districts use Blackboard Learn to support blended classroom instruction and remote learning days.$q$, $q$K-12 school districts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Accessible course delivery$q$, $q$Institutions with accessibility compliance requirements use Ally to generate alternative content formats automatically.$q$, $q$Accessibility and disability services offices$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Blackboard Learn is a learning management system that originated with Blackboard Inc. in 1997 and is now developed by Anthology, Inc., formed from Blackboard's 2021 merger with Anthology. Anthology is headquartered in Boca Raton, Florida, with over 1,000 employees across North America and international offices.$q$, $q$The platform is used mainly by higher-education institutions and K-12 school systems to host online and blended courses, manage grading and assignments, and track student progress and engagement over the course of a term.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Ultra Course View is Blackboard's modern, mobile-first interface, offering streamlined navigation, Progress Tracking, and Discussion Analytics compared with the legacy Original Course View. The Ally accessibility tool scans course materials and automatically generates alternative formats such as audio and ePub for students with different accessibility needs.$q$, $q$Anthology has also introduced an Ultra AI Design Assistant aimed at helping instructors build course structures and content more efficiently, alongside standard LMS capabilities like gradebooks, discussion boards, assignment submission, and LTI-based integrations with third-party publisher and proctoring tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Blackboard Learn does not list fixed public pricing. Anthology sells the platform through negotiated institutional contracts, with cost driven by enrollment size, deployment model, and which additional Anthology products are bundled in.$q$, $q$Institutions typically need to request a quote directly from Anthology's sales team; publicly cited reference figures vary widely by region and procurement framework, so they should not be treated as a reliable list price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Network-wide DNS filtering$q$, $q$Blocks ads, trackers, and malware domains for every device on the network via DNS interception.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Deep CNAME inspection$q$, $q$Blocks domains based on their CNAME resolution chain, catching cloaked tracking domains that plain blocklists miss.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Encrypted DNS protocol support$q$, $q$Supports DNS-over-HTTPS, DNS-over-TLS, and DNS-over-QUIC for both upstream and downstream queries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Database-backed query logging$q$, $q$Logs DNS queries per client to CSV or to MySQL, PostgreSQL, MariaDB, or TimescaleDB.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Prometheus metrics$q$, $q$Exposes metrics for integration with Prometheus and Grafana monitoring stacks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$No telemetry$q$, $q$Collects no usage data and shares nothing with third parties by design.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Completely free and open source with no account or subscription required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Lightweight Go implementation with low resource usage, suitable for a Raspberry Pi$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Supports modern encrypted DNS protocols and DNSSEC$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$No telemetry or data collection$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Requires self-hosting and configuration file editing rather than a plug-and-play setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$No official customer support beyond community GitHub issues$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$No graphical onboarding wizard for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Depends entirely on the user for updates, maintenance, and uptime$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Is blocky free to use?$q$, $q$Yes, blocky is completely free and open source with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Do I need to self-host blocky?$q$, $q$Yes, blocky is a self-hosted DNS proxy that you run on your own server, Raspberry Pi, or NAS; there is no managed cloud version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$How is blocky different from Pi-hole?$q$, $q$Both are self-hosted DNS ad blockers, but blocky is written in Go and adds features like deep CNAME inspection and native support for encrypted DNS protocols such as DoH, DoT, and DoQ.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Does blocky collect any data?$q$, $q$No, blocky states it collects no telemetry and shares no data with any third party.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Home network ad blocking$q$, $q$A household runs blocky on a Raspberry Pi or home server to block ads and trackers for every device on the network.$q$, $q$Home lab and privacy-focused users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$Self-hosted infrastructure monitoring$q$, $q$A self-hoster integrates blocky's Prometheus metrics and database query logs into an existing Grafana monitoring stack.$q$, $q$Self-hosting and homelab administrators$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$blocky is a free, open-source DNS proxy and ad-blocker written in Go, maintained on GitHub as a volunteer project with no company or commercial backing. It runs as a self-hosted service on a local network and blocks ads, trackers, and malware domains at the DNS level for every connected device.$q$, $q$Because it intercepts DNS requests directly rather than filtering inside a browser, blocky blocks unwanted content across an entire network at once, including apps, smart TVs, and IoT devices that browser extensions cannot reach.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$blocky supports domain-based blocklists, deep CNAME inspection to catch cloaked tracking domains, and IP-based blocking. It supports encrypted DNS protocols including DNS-over-HTTPS, DNS-over-TLS, and DNS-over-QUIC, as well as DNSSEC validation.$q$, $q$Query logging can be written to CSV files or to a database such as MySQL, PostgreSQL, MariaDB, or TimescaleDB, and blocky exposes Prometheus-compatible metrics for integration with monitoring dashboards like Grafana.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$blocky is free and open source with no paid tiers, subscriptions, or commercial support plans. It is typically deployed via Docker or as a standalone binary and configured through a YAML file, so the only cost is the hardware or hosting used to run it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68da8924-7233-4187-b3c7-8e5486ea5ee0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Folder-to-website publishing$q$, $q$Files added to a connected Dropbox, Google Drive, or GitHub folder are automatically published as web pages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$No dashboard required$q$, $q$There is no separate CMS login; editing and organizing files in the synced folder is the entire publishing workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Markdown and document support$q$, $q$Supports Markdown, plain text, and common document formats as source files for posts and pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Custom themes$q$, $q$A library of templates can be applied and customized with HTML and CSS for design control.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Custom domains and SSL$q$, $q$Hosted plan includes custom domain support and SSL certificates out of the box.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Open-source self-hosting$q$, $q$Full source code is published on GitHub, allowing self-hosted deployments instead of Blot's paid hosting.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Extremely low-friction publishing workflow with no CMS interface to learn$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Works with tools writers already use, like Dropbox, Google Drive, and GitHub$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Open-source codebase available for self-hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Affordable flat pricing at $6/month per site$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$No free tier or trial period advertised$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Not designed for team collaboration or multi-author workflows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Lacks the plugin and app ecosystem of larger platforms like WordPress$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Requires comfort with file-based, folder-driven organization rather than a visual editor$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$How much does Blot cost?$q$, $q$Blot's hosted plan costs $6 per month per site, covering hosting, templates, custom domain support, and SSL certificates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$How does Blot's folder-to-website system work?$q$, $q$You connect a folder in Dropbox, Google Drive, or GitHub to Blot, and any file you add, edit, or delete in that folder is automatically published, updated, or removed on your live website.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Is Blot open source?$q$, $q$Yes, Blot's source code is published on GitHub, and technically capable users can self-host their own instance instead of paying for Blot's hosted service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Who created Blot?$q$, $q$Blot was created by developer David Merfield, who began building it in 2013 and released it publicly in 2014.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Minimalist personal blogging$q$, $q$A writer publishes posts by saving Markdown or Word files into a synced Dropbox folder, with no CMS login required.$q$, $q$Individual writers and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Developer-managed sites via Git$q$, $q$A developer manages a personal site or documentation blog by pushing files to a connected GitHub repository.$q$, $q$Developers and indie hackers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$Hosted$q$, $q$$6/month$q$, $q$Per site, monthly (annual option available)$q$, NULL, $q$["Hosting","All templates","Custom domain support","SSL certificate","Customer support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Blot is a blogging platform created by developer David Merfield, who began working on it in 2013 and released it publicly in 2014. It is best known for having no traditional content management interface: users connect a folder in Dropbox, Google Drive, or GitHub, and any file added to that folder becomes a page on a live website automatically.$q$, $q$The project is explicitly framed as an attempt to bring back the simplicity of early web publishing, letting anyone start a website with something as simple as a Word document while still producing a fast, themeable, modern site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Blot supports Markdown, plain text, and rich document formats as source files, automatically converting them into formatted web pages. Site structure, including nested pages and categories, is managed entirely through folder organization in the connected cloud storage account rather than a web dashboard.$q$, $q$The platform offers a library of customizable templates, custom domain support, and SSL certificates on its hosted plan. Because Blot is also open source, technically capable users can self-host their own instance instead of using Blot's paid hosting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Blot's hosted service costs $6 per month per site, which includes hosting, access to all templates, custom domain support, and SSL certificates. There is no published free trial; users sign up directly for the paid plan or choose to self-host the open-source code instead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53ba4185-9c98-4925-94b6-7aa6336c54d0', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Podcast media hosting$q$, $q$Hosts podcast audio files and generates the RSS feed used to distribute episodes to podcast apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$IAB-certified analytics$q$, $q$Download and audience statistics certified to Interactive Advertising Bureau standards, used for ad sales reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$WordPress integration$q$, $q$All hosting plans include a free WordPress companion site, and the PowerPress plugin integrates hosting into existing WordPress sites.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Custom embed player$q$, $q$A customizable audio player can be embedded on any website to play hosted episodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Multi-show and network management$q$, $q$The Professional plan supports managing multiple shows and user accounts under one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Dynamic ad insertion$q$, $q$Professional plan supports advanced monetization tools including dynamic ad insertion for commercial podcasts.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$One of the longest-running podcast hosts, operating since 2005$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$IAB-certified analytics are useful for creators selling ads based on verified downloads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Free WordPress companion site and PowerPress plugin integration included$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Free statistics tier available even for shows hosted elsewhere$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Storage-based upload limits on lower tiers can constrain frequent or long-form publishers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Professional plan at $100/month is a large jump from the Advanced tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Headquarters and company size are not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Less brand recognition today compared to newer hosts like Spotify for Podcasters or Buzzsprout$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$How much does Blubrry cost?$q$, $q$Podcast hosting starts at $15/month for the Standard plan (125 MB uploads), $25/month for Advanced (400 MB uploads), and $100/month for unlimited Professional hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Does Blubrry offer free statistics?$q$, $q$Yes, Blubrry offers a Free Statistics tier that tracks basic downloads, audience location, and listener trends even if your podcast is hosted elsewhere.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Is Blubrry's analytics IAB certified?$q$, $q$Yes, all Blubrry statistics plans are IAB certified, a standard commonly required for verified ad sales reporting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Does Blubrry integrate with WordPress?$q$, $q$Yes, all hosting plans include a free companion WordPress site, and Blubrry's PowerPress plugin adds podcast publishing directly to an existing WordPress site.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Who founded Blubrry?$q$, $q$Blubrry was founded in 2005 by podcast pioneer Todd Cochrane, who led the company as CEO until his death in September 2025.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Independent podcast hosting$q$, $q$A solo podcaster hosts episodes, distributes to Apple Podcasts and Spotify, and tracks IAB-certified downloads.$q$, $q$Independent podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$WordPress-based podcast publishing$q$, $q$A blogger adds a podcast to an existing WordPress site using the PowerPress plugin and Blubrry hosting.$q$, $q$WordPress site owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Commercial podcast networks$q$, $q$A network manages multiple shows, unlimited uploads, and dynamic ad insertion under the Professional plan.$q$, $q$Podcast networks and commercial publishers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Standard Hosting$q$, $q$$15/month$q$, $q$Monthly$q$, NULL, $q$["125 MB monthly uploads","Unlimited listens","Distribution to major platforms","Free WordPress site"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Advanced Hosting$q$, $q$$25/month$q$, $q$Monthly$q$, NULL, $q$["400 MB monthly uploads","Deeper audience analytics","Episode performance tools","Advanced Statistics included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Professional Hosting$q$, $q$$100/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited uploads","Multiple shows and users","Advanced monetization","Dynamic ad insertion"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Free Statistics$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Basic download tracking","Audience location","Listener trends"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$Standard Statistics$q$, $q$$5/month$q$, $q$Monthly$q$, NULL, $q$["Full audience and device data","3-episode comparison","Media kit creation"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Blubrry Podcasting was founded in 2005 by podcast pioneer Todd Cochrane, one of the earliest companies in podcast hosting, with more than 20 years in the industry. Cochrane led the company as CEO until his death in September 2025.$q$, $q$Blubrry hosts podcast audio files, generates the RSS feed used by podcast apps, and distributes episodes to platforms including Apple Podcasts and Spotify, alongside standalone analytics products for creators hosted elsewhere.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hosting plans are tiered by monthly upload storage rather than downloads, and all tiers include unlimited listens, distribution to major podcast directories, a free WordPress companion site, and a custom embeddable player.$q$, $q$Blubrry's statistics are IAB certified, a standard used for verified audience reporting in ad sales, and the company is also known for its PowerPress WordPress plugin that integrates podcast publishing directly into a WordPress site.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Podcast hosting starts at $15 per month for the Standard plan (125 MB monthly uploads), $25 per month for the Advanced plan (400 MB monthly uploads), and $100 per month for the Professional plan with unlimited uploads and multi-show management.$q$, $q$Standalone statistics plans range from a free tier with basic download and location data to a $5 per month Standard Statistics tier, with Advanced Statistics included as part of the Advanced hosting plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e9b75f81-ed9a-4a4b-93e5-70d03b1fd25e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Flat-file, database-free storage$q$, $q$Content, pages, and settings are stored as JSON files instead of requiring a database server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Markdown and WYSIWYG editing$q$, $q$Supports both a Markdown editor and a rich text WYSIWYG editor for writing content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Plugin and theme ecosystem$q$, $q$Extendable through community plugins and themes distributed via an official plugins directory.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Built-in SEO tools$q$, $q$Includes SEO features out of the box to help improve search engine ranking without additional plugins.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Privacy-first, no tracking$q$, $q$Does not track visitors by default and is positioned as GDPR compliant.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Docker and web installer support$q$, $q$Can be deployed through a standard web-based installer or containerized via Docker.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$No database required, simplifying installation, backups, and hosting requirements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Free and open source under the permissive MIT license$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Lightweight and fast, suitable for standard shared hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Built-in SEO tools and privacy-first, no default visitor tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$No built-in multi-language admin interface without third-party plugins$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Smaller plugin and theme ecosystem compared to WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Flat-file storage can be less efficient than a database at larger content scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$No official company or commercial support; relies on community forums$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Is Bludit free to use?$q$, $q$Yes, Bludit is completely free and open source under the MIT license, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Does Bludit require a database?$q$, $q$No, Bludit is a flat-file CMS that stores all content as JSON files on the file system, so no database server is needed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Can Bludit be extended with plugins and themes?$q$, $q$Yes, Bludit has an official plugins and themes directory maintained by the community, covering functionality like contact forms, galleries, and SEO tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$What are the server requirements for Bludit?$q$, $q$Bludit requires PHP 7 or higher along with the mbstring, GD, DOM, and JSON PHP extensions; no database is required.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Is Bludit good for multilingual websites?$q$, $q$Bludit's core admin interface lacks native multi-language switching, so multilingual sites typically rely on community plugins or separate installations per language.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Simple personal or small-business blogs$q$, $q$A site owner runs a low-maintenance blog on standard shared hosting without needing to manage a database.$q$, $q$Individuals and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$Portfolio and documentation sites$q$, $q$A developer or designer builds a fast-loading portfolio or documentation site using Bludit's flat-file simplicity.$q$, $q$Developers and freelancers$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bludit is a free, open-source flat-file CMS that has been in active development since 2015 and is released under the MIT license. Instead of using a database, it stores all content, pages, and settings as JSON files directly on the server's file system.$q$, $q$This architecture means the only server requirement is PHP with a handful of standard extensions, making Bludit faster to install and simpler to maintain than database-driven platforms, since there is no database server to configure or back up.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bludit supports both a Markdown editor and a WYSIWYG rich text editor, plus raw HTML in content. It includes built-in SEO tools and is designed to be privacy-first, tracking no visitor data by default.$q$, $q$Like larger CMS platforms, Bludit can be extended with community plugins and themes distributed through an official plugins directory, covering contact forms, galleries, RSS feeds, and SEO utilities, and it can be deployed via a web installer or Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bludit is completely free and open source under the MIT license, with no paid tiers, subscriptions, or commercial support plans. Costs are limited to whatever web hosting or server the user chooses to run it on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2dacf89b-e2ef-4c5b-abc5-d221801f171b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Digital storefront$q$, $q$Gives distributors an online ordering interface for restaurant and foodservice buyers to browse and place orders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Order management dashboard$q$, $q$Streamlines receiving, confirming, fulfilling, and tracking buyer orders in one system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Pricing Insights$q$, $q$Benchmarks a distributor's product pricing against market data and flags items as Great, Good, or Fair Value.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Endless Aisle Marketplace$q$, $q$Connects vendors to a network described as 48,000-plus transacting restaurants and foodservice businesses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Inventory and invoicing$q$, $q$Tracks stock levels and manages invoicing and payment collection alongside order processing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Buyer CRM$q$, $q$Manages customer relationships, order history, and reorder patterns for foodservice buyers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Flexible delivery zones and fulfillment$q$, $q$Configurable delivery areas by state and city, supporting local delivery, nationwide shipping, or third-party logistics.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Purpose-built specifically for food and beverage wholesale distribution rather than generic ecommerce$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Marketplace access can generate new restaurant demand beyond a distributor's existing customer base$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Combines storefront, inventory, invoicing, and CRM in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Backed by $31M in funding with an established track record since 2014$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$No public pricing; requires booking a demo to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Built specifically for food and beverage distribution, limiting fit for other wholesale categories$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Smaller company size may mean less extensive support resources than larger enterprise platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Feature depth for non-food wholesale verticals is not clearly documented$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$How much does BlueCart cost?$q$, $q$BlueCart does not publish pricing publicly; prospective customers need to book a demo with the sales team to get a quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Who is BlueCart for?$q$, $q$BlueCart is built for food and beverage wholesale distributors, including coffee, meat, seafood, dairy, bakery, and produce suppliers, and the restaurants and foodservice businesses that buy from them.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$When was BlueCart founded?$q$, $q$BlueCart was founded in 2014 by Jag Bansal and Konstantin Zvereff and is headquartered in Sunnyvale, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$What is BlueCart's Endless Aisle Marketplace?$q$, $q$It's a network that gives BlueCart vendors access to a described base of more than 48,000 transacting restaurants and foodservice businesses for order discovery.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Does BlueCart handle inventory and invoicing?$q$, $q$Yes, BlueCart combines a digital storefront with order management, inventory tracking, invoicing, and a buyer CRM in one platform.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Food and beverage distributor digitization$q$, $q$A wholesale distributor replaces phone and fax order-taking with a digital storefront and order management dashboard.$q$, $q$Food and beverage distributors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Restaurant and foodservice buying$q$, $q$A restaurant or cafe orders supplies from multiple distributors through BlueCart's marketplace and buyer tools.$q$, $q$Restaurants, cafes, and hotels$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$Competitive pricing management$q$, $q$A distributor uses Pricing Insights to benchmark and adjust product pricing against market data.$q$, $q$Wholesale sales and pricing teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BlueCart was founded in 2014 by Jag Bansal and Konstantin Zvereff and is headquartered in Sunnyvale, California. The company has raised roughly $31 million in funding and employs an estimated 51 to 200 people.$q$, $q$BlueCart is a B2B ecommerce and business management platform built specifically for food and beverage wholesale distribution, connecting distributors with the restaurants, cafes, and foodservice businesses that order from them.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines a digital storefront, order management dashboard, inventory tracking, invoicing, and buyer CRM in one system. Its Endless Aisle Marketplace connects vendors with a network the company describes as more than 48,000 transacting restaurants and foodservice buyers.$q$, $q$A Pricing Insights tool benchmarks product pricing against market data, and distributors can configure delivery zones by state and city, run promotions like free delivery for new customers, and choose between local delivery, nationwide shipping, or third-party logistics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BlueCart does not publish self-serve pricing. Prospective distributor customers are directed to book a demo with BlueCart's sales team, and pricing is understood to be quote-based, likely varying with order volume and which modules are included.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1947c7c-e691-4991-bc52-01c2627b4ff1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
